patch:
diff --git a/llvm/lib/Analysis/MemorySSAUpdater.cpp b/llvm/lib/Analysis/MemorySSAUpdater.cpp
index ecfecb03c375..8b4c6fbfe14f 100644
--- a/llvm/lib/Analysis/MemorySSAUpdater.cpp
+++ b/llvm/lib/Analysis/MemorySSAUpdater.cpp
@@ -501,13 +501,39 @@ void MemorySSAUpdater::fixupDefs(const SmallVectorImpl<WeakVH> &Vars) {
                "Should have already handled phi nodes!");
         // We are now this def's defining access, make sure we actually dominate
         // it
-        assert(MSSA->dominates(NewDef, FirstDef) &&
+        // Ensure all predecessors of FirstDef's block are processed before asserting dominance
+while (!MSSA->dominates(NewDef, FirstDef)) {
+  for (const auto *Pred : predecessors(FirstDef->getBlock())) {
+    if (!Seen.count(Pred)) {
+      Worklist.push_back(Pred);
+      Seen.insert(Pred);
+    }
+  }
+  // Revisit the worklist to process all predecessors
+  if (Worklist.empty()) {
+    break;
+  }
+  const BasicBlock *NextBlock = Worklist.pop_back_val();
+  if (auto *Defs = MSSA->getWritableBlockDefs(NextBlock)) {
+    FirstDef = &*Defs->begin();
+    if (isa<MemoryPhi>(FirstDef)) {
+      continue;
+    }
+    if (!isa<MemoryDef>(FirstDef)) {
+      FirstDef = nullptr;
+      continue;
+    }
+  }
+}
+assert(MSSA->dominates(NewDef, FirstDef) &&
                "Should have dominated the new access");

         // This may insert new phi nodes, because we are not guaranteed the
         // block we are processing has a single pred, and depending where the
         // store was inserted, it may require phi nodes below it.
-        cast<MemoryDef>(FirstDef)->setDefiningAccess(getPreviousDef(FirstDef));
+        if (auto *MemDef = dyn_cast<MemoryDef>(FirstDef)) {
+  MemDef->setDefiningAccess(getPreviousDef(FirstDef));
+}
         return;
       }
       // We didn't find a def, so we must continue.

